package com.lagradost.cloudstream3.extractorsimport com.lagradost.cloudstream3.SubtitleFileimport com.lagradost.cloudstream3.appimport com.lagradost.cloudstream3.base64Decodeimport com.lagradost.cloudstream3.utils.ExtractorApiimport com.lagradost.cloudstream3.utils.ExtractorLinkimport com.lagradost.cloudstream3.utils.loadExtractorclass Kotakajaib : ExtractorApi() {    override val name = "Kotakajaib"    override val mainUrl = "https://kotakajaib.me"    override val requiresReferer = true    override suspend fun getUrl(        url: String,        referer: String?,        subtitleCallback: (SubtitleFile) -> Unit,        callback: (ExtractorLink) -> Unit    ) {        val response = app.get(            url = url,            referer = referer        )        val servers = response.document.select("ul#dropdown-server li a")        servers.forEach { element ->            val encoded = element.attr("data-frame")            if (encoded.isBlank()) return@forEach            val decodedUrl = base64Decode(encoded)            val extractorReferer = "$mainUrl/"            loadExtractor(                decodedUrl,                extractorReferer,                subtitleCallback,                callback            )        }    }}